2058 |     function b64DecodeUnicode(str) {
2059 |         const binString = atob(str);
2060 |         const bytes = Uint8Array.from(binString, (m) => m.charCodeAt(0));
2061 |         return new TextDecoder().decode(bytes);
2062 |     }
