2064 |     function b64EncodeUnicode(str) {
2065 |         const bytes = new TextEncoder().encode(str);
2066 |         const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
2067 |         return btoa(binString);
2068 |     }
