2070 |     function base64ToUint8Array(base64) {
2071 |         const binaryString = atob(base64);
2072 |         const bytes = new Uint8Array(binaryString.length);
2073 |         for (let i = 0; i < binaryString.length; i++) {
2074 |             bytes[i] = binaryString.charCodeAt(i);
