2290 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2291 |     function applyLocalPatch(content, ops) {
2292 |         let lines = content.split('\n');
2293 |         let logs = [];
2294 |         let success = true;
2295 | 
2296 |         if (typeof ops === 'string') {
2297 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2298 |         }
2299 | 
2300 |         ops.forEach(op => {
2301 |             if (op.action === 'comment') return;
2302 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2303 |             
2304 |             if (op.action === 'replace_block') {
2305 |                 // Strategy 1: Exact String Match (Fastest)
2306 |                 const currentStr = lines.join('\n');
2307 |                 if (currentStr.includes(op.find_block)) {
2308 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2309 |                     logs.push('Exact match applied');
2310 |                     return;
2311 |                 }
2312 | 
2313 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2314 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2315 |                 if (searchLines.length === 0) return;
2316 | 
2317 |                 let matchStart = -1;
2318 |                 let matchEnd = -1;
2319 | 
2320 |                 // Scan file lines
2321 |                 for (let i = 0; i < lines.length; i++) {
2322 |                     // If first line matches (ignoring whitespace)
2323 |                     if (lines[i].trim() === searchLines[0]) {
2324 |                         // Check subsequent lines
2325 |                         let allMatch = true;
2326 |                         let fileOffset = 0;
2327 |                         let searchOffset = 1;
2328 |                         
2329 |                         while (searchOffset < searchLines.length) {
2330 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2331 |                             const nextFile = lines[i + fileOffset + 1].trim();
2332 |                             // Skip empty lines in file if they aren't in search block
2333 |                             if (nextFile === '') {
2334 |                                 fileOffset++;
2335 |                                 continue;
2336 |                             }
2337 |                             if (nextFile !== searchLines[searchOffset]) {
2338 |                                 allMatch = false;
2339 |                                 break;
2340 |                             }
2341 |                             fileOffset++;
2342 |                             searchOffset++;
2343 |                         }
2344 | 
2345 |                         if (allMatch) {
2346 |                             matchStart = i;
2347 |                             matchEnd = i + fileOffset;
2348 |                             break;
2349 |                         }
2350 |                     }
2351 |                 }
2352 | 
2353 |                 if (matchStart !== -1) {
2354 |                     // Replace the range of lines
2355 |                     const replacement = op.replace_with.split('\n');
2356 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2357 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2358 |                 } else {
2359 |                     success = false;
2360 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2361 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2362 |                 }
2363 |             }
2364 |         });
2365 |         return { content: lines.join('\n'), success, logs };
2366 |     }
