5202 |     function timeAgo(dateString) {
5203 |         const date = new Date(dateString);
5204 |         const now = new Date();
5205 |         const seconds = Math.floor((now - date) / 1000);
5206 |         if (seconds < 10) return 'just now';
5207 |         if (seconds < 60) return seconds + 's ago';
5208 |         const minutes = Math.floor(seconds / 60);
5209 |         if (minutes < 60) return minutes + 'm ago';
5210 |         const hours = Math.floor(minutes / 60);
5211 |         if (hours < 24) return hours + 'h ago';
5212 |         return date.toLocaleDateString();
5213 |     }
