7925 |     function extractTableNames(sql) {
7926 |         if (!sql) return [];
7927 |         const tables = [];
7928 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7929 |         
7930 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7931 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7932 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7933 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7934 | 
7935 |         let match;
7936 |         while ((match = fromRegex.exec(sql)) !== null) {
7937 |             const name = match[1];
7938 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7939 |                 tables.push(name);
7940 |             }
7941 |         }
7942 |         
7943 |         while ((match = metaRegex.exec(sql)) !== null) {
7944 |             const name = match[1];
7945 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7946 |                 tables.push(name);
7947 |             }
7948 |         }
7949 | 
7950 |         return tables;
7951 |     }
